"use strict";function showHideMobileLinks(e){let t=e.getAttribute("class");t.includes("mobile_closed")?(t=t.replace("mobile_closed","mobile_opened"),e.setAttribute("class",t)):t.includes("mobile_opened")&&(t=t.replace("mobile_opened","mobile_closed"),e.setAttribute("class",t))}window.addEventListener("DOMContentLoaded",function(){let e=document.querySelectorAll(".catalog-section_item");for(let t=0;t<e.length;t++)if(e[t].querySelector(".items_links-mobile")){let l=e[t].querySelector(".icon-nav_button-mobile_wrapper");e[t].setAttribute("class",e[t].getAttribute("class")+" mobile_closed"),l.addEventListener("click",function(){showHideMobileLinks(e[t])})}});